static struct pid *
pdes_get(int *pdes, const char **type)
{
	struct pid *cur;
	int flags = strchr(*type, 'e') ? O_CLOEXEC : 0;
	int serrno;

	if (strchr(*type, '+')) {
#ifndef SOCK_CLOEXEC
#define SOCK_CLOEXEC 0
#endif
		int stype = flags ? (SOCK_STREAM | SOCK_CLOEXEC) : SOCK_STREAM;
		*type = "r+";
		if (socketpair(AF_LOCAL, stype, 0, pdes) < 0)
			return NULL;
#if SOCK_CLOEXEC == 0
		fcntl(pdes[0], F_SETFD, FD_CLOEXEC);
		fcntl(pdes[1], F_SETFD, FD_CLOEXEC);
#endif
	} else  {
		*type = strrchr(*type, 'r') ? "r" : "w";
#if SOCK_CLOEXEC != 0
		if (pipe2(pdes, flags) == -1)
			return NULL;
#else
		if (pipe(pdes) == -1)
			return NULL;
		fcntl(pdes[0], F_SETFL, fcntl(pdes[0], F_GETFL) | flags);
		fcntl(pdes[1], F_SETFL, fcntl(pdes[1], F_GETFL) | flags);
#endif
	}

	if ((cur = malloc(sizeof(*cur))) != NULL) {
		if (**type == 'r') {
			cur->fp = fdopen(pdes[0], *type);
#ifdef _REENTRANT
			cur->fd = pdes[0];
#endif
		} else {
			cur->fp = fdopen(pdes[1], *type);
#ifdef _REENTRANT
			cur->fd = pdes[1];
#endif
		}
		if (cur->fp != NULL)
			return cur;
	}
	serrno = errno;
	(void)close(pdes[0]);
	(void)close(pdes[1]);
	free(cur);
	errno = serrno;
	return NULL;
}

