static void
pdes_parent(int *pdes, struct pid *cur, pid_t pid, const char *type)
{
	/* Parent */
	if (*type == 'r')
		(void)close(pdes[1]);
	else
		(void)close(pdes[0]);

	/* Link into list of file descriptors. */
	cur->pid = pid;
	cur->next = pidlist;
	pidlist = cur;
}

